def gen(rng, size):
    n = rng.randint(1, 40)
    pool = list('abcd') + ['*', '#', '%']
    s = ''.join(rng.choice(pool) for _ in range(n))
    CAP = 1 << 60
    length = 0
    for ch in s:
        if ch == '*':
            if length > 0:
                length -= 1
        elif ch == '#':
            length = min(CAP, length * 2)
        elif ch == '%':
            pass
        else:
            length += 1
    hi = max(length, 1)
    k = rng.randint(0, hi + 2)
    return [s, k]

