class Solution:
    def processStr(self, s, k):
        res = []
        for ch in s:
            if ch == '*':
                if res:
                    res.pop()
            elif ch == '#':
                res = res + res
            elif ch == '%':
                res = res[::-1]
            else:
                res.append(ch)
        if 0 <= k < len(res):
            return res[k]
        return '.'

