class Solution:
    def processStr(self, s, k):
        lengths = [0]
        L = 0
        for ch in s:
            if ch == '*':
                if L > 0:
                    L -= 1
            elif ch == '#':
                L = L * 2
            elif ch == '%':
                pass
            else:
                L += 1
            lengths.append(L)
        if k < 0 or k >= lengths[-1]:
            return '.'
        idx = k
        for i in range(len(s) - 1, -1, -1):
            ch = s[i]
            prev = lengths[i]
            if ch == '*':
                pass
            elif ch == '#':
                if idx >= prev:
                    idx -= prev
            elif ch == '%':
                idx = prev - 1 - idx
            else:
                if idx == prev:
                    return ch
        return '.'

