var processStr = function(s, k) {
    const lengths = [0n];
    let L = 0n;
    const kk = BigInt(k);
    for (const ch of s) {
        if (ch === '*') {
            if (L > 0n) L -= 1n;
        } else if (ch === '#') {
            L = L * 2n;
        } else if (ch === '%') {
            // no length change
        } else {
            L += 1n;
        }
        lengths.push(L);
    }
    if (kk < 0n || kk >= lengths[lengths.length - 1]) return '.';
    let idx = kk;
    for (let i = s.length - 1; i >= 0; i--) {
        const ch = s[i];
        const prev = lengths[i];
        if (ch === '*') {
            // index unchanged
        } else if (ch === '#') {
            if (idx >= prev) idx -= prev;
        } else if (ch === '%') {
            idx = prev - 1n - idx;
        } else {
            if (idx === prev) return ch;
        }
    }
    return '.';
};
